def evaluate(s):
    nums = []
    ops  = []
    i, n = 0, len(s)

    def apply_op():
        b, a = nums.pop(), nums.pop()
        op   = ops.pop()
        if   op == '+': nums.append(a + b)
        elif op == '-': nums.append(a - b)
        elif op == '*': nums.append(a * b)
        elif op == '/': nums.append(int(a / b))  # truncate toward zero

    PREC = {'+': 1, '-': 1, '*': 2, '/': 2}

    while i < n:
        if s[i] == ' ':
            i += 1; continue
        if s[i].isdigit():
            j = i
            while j < n and s[j].isdigit(): j += 1
            nums.append(int(s[i:j]))
            i = j
        else:
            # Before pushing op, apply all ops of >= precedence
            while ops and ops[-1] in PREC and ___________:
                apply_op()
            ops.append(s[i]); i += 1
    while ops:
        apply_op()
    return nums[0]
